import{_ as i,o as t,c as o,j as a,a as l,G as n,a3 as s,B as d}from"./chunks/framework.DpCrEuUp.js";const w=JSON.parse('{"title":"雪地冲突","description":"","frontmatter":{},"headers":[],"relativePath":"map/done/snowy-skirmish.md","filePath":"map/done/snowy-skirmish.md","lastUpdated":1734620100000}'),p={name:"map/done/snowy-skirmish.md"};function c(m,e,h,f,u,k){const r=d("ArticleMetadata");return t(),o("div",{"data-pagefind-body":!0},[e[0]||(e[0]=a("h1",{id:"雪地冲突",tabindex:"-1"},[l("雪地冲突 "),a("a",{class:"header-anchor",href:"#雪地冲突","aria-label":'Permalink to "雪地冲突"'},"​")],-1)),n(r),e[1]||(e[1]=s('<figure><img src="https://ypy-uss.yuwan886.top/YW-docs/map/snowy-skirmish/snowy-skirmish.jpg" alt="我是封面" tabindex="0" loading="lazy"><figcaption>我是封面</figcaption></figure><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><ul><li>作者：<a href="https://www.planetminecraft.com/member/zeroniaserver/" target="_blank" rel="noreferrer">ZeroniaServer</a></li><li>原址：<a href="https://www.planetminecraft.com/project/snowy-skirmish/" target="_blank" rel="noreferrer">PMC</a></li><li>版本：1.21.3</li><li>类型：<code>多人</code> <code>PVP</code> <code>MiniGames</code></li><li>汉化：<a href="https://pan.quark.cn/s/05ad4fc53b7d" target="_blank" rel="noreferrer">下崽</a></li></ul><h2 id="介绍" tabindex="-1">介绍 <a class="header-anchor" href="#介绍" aria-label="Permalink to &quot;介绍&quot;">​</a></h2><blockquote><p>☃️ .<em>・ ‧❄。゚ •</em>・ Snowy Skirmish ・<em>• ゚。❄ ‧ ・</em>.☃️</p><p>将休闲打雪仗提升到一个新的水平！</p></blockquote><h3 id="特点" tabindex="-1">特点 <a class="header-anchor" href="#特点" aria-label="Permalink to &quot;特点&quot;">​</a></h3><p>雪地冲突是一场快速而有趣的打雪仗，玩家需要收集礼物盒或将对手从地图上击倒，才能为他们的团队获得积分。</p><p>在游戏开始时的准备阶段，玩家会获得雪块壁垒，他们可以用它来建造堡垒作为掩体或有利位置。</p><p>当准备阶段结束时，玩家会获得雪球，他们必须与敌人战斗并收集礼物盒才能获胜。</p><p>可以通过消灭敌人或捡起蓝色礼物盒来收集积分。</p><p>道具是用于协助您或您的队友的特殊武器或实用物品。这些可以从地图上偶尔生成的红色礼盒中解锁。</p><h3 id="增益" tabindex="-1">增益 <a class="header-anchor" href="#增益" aria-label="Permalink to &quot;增益&quot;">​</a></h3><ul><li>冰球：一种射程有限的坚固冰球，能够一击击倒敌人。</li><li>热巧克力：消耗品;玩家可以喝热巧克力来快速恢复一些生命值，而被淘汰的玩家可以用它来恢复自己。</li><li>雪球炮塔：一个友好的雪人，会向靠近它的敌方玩家发射一阵阵雪球。它们可以用雪球和冰球摧毁，并且会随着时间的推移而融化。</li><li>瓶中暴风雪：在它降落的地方制造一团暴风雨云。当敌人站在它的范围内时，他们会变慢并受到大量伤害。当你站在自己团队的暴风雪中时，你会更快地得到雪球。</li><li>糖果拐杖粉碎者：近战武器，用于对敌方玩家造成大量伤害和击退。</li><li>营火复活点：一堆小型营火; 当被击倒的盟友接近此点时，他们会在还剩 1 颗心的情况下复活。</li><li>雪橇：让您在地图上快速移动，让您更难被击中。乘坐雪橇从悬崖上跳下来，进行一次大跳跃。当没有人骑雪橇或经过几次大跳跃时，雪橇会随着时间的推移而断裂。</li></ul>',13))])}const y=i(p,[["render",c]]);export{w as __pageData,y as default};
